    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(k + 1, LLONG_MAX)));

    pq.push({0, 0, 0, k});
    dist[0][0][k] = 0;

    while (!pq.empty()) {
        auto [cost, i, j, rem_k] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (cost > dist[i][j][rem_k]) {
            continue;
        }

        // Normal moves (right and down)
        for (auto [di, dj] : dirs) {
            int ni = i + di;
            int nj = j + dj;
            if (ni < m && nj < n) {
                long long new_cost = cost + grid[ni][nj];
                if (new_cost < dist[ni][nj][rem_k]) {
                    dist[ni][nj][rem_k] = new_cost;
                    pq.push({new_cost, ni, nj, rem_k});
                }
            }
        }

        // Teleport move
        if (rem_k > 0) {
            for (int ni = 0; ni < m; ++ni) {
                for (int nj = 0; nj < n; ++nj) {
                    if (ni == i && nj == j) continue;
                    if (grid[ni][nj] <= grid[i][j]) {
                        long long new_cost = cost;
                        if (new_cost < dist[ni][nj][rem_k - 1]) {
                            dist[ni][nj][rem_k - 1] = new_cost;
                            pq.push({new_cost, ni, nj, rem_k - 1});
                        }
                    }
                }
            }
        }
    }

    return -1; // Should not reach here if path exists
}
